import { readFileSync, realpathSync } from "node:fs";
import { z } from "zod";

const GitSnapshotSchema = z
  .object({
    head: z.string().nullable(),
    branch: z.string().nullable(),
    status: z.string().nullable(),
    diff: z.string().nullable(),
    errors: z.array(z.string())
  })
  .loose();

const CapturedRecordSchema = z
  .object({
    capture: z
      .object({
        schemaVersion: z.number(),
        capturedAt: z.string().min(1),
        sessionId: z.string().nullable(),
        eventName: z.string().nullable(),
        validationErrors: z.array(z.string()).optional(),
        git: GitSnapshotSchema.optional()
      })
      .loose(),
    payload: z.unknown()
  })
  .loose();

const CommonPayloadSchema = z
  .object({
    session_id: z.string().optional(),
    hook_event_name: z.string().optional(),
    cwd: z.string().optional(),
    model: z.string().optional(),
    turn_id: z.string().optional()
  })
  .loose();

const SessionStartPayloadSchema = CommonPayloadSchema.extend({
  hook_event_name: z.literal("SessionStart"),
  source: z.string().optional()
}).loose();

const UserPromptPayloadSchema = CommonPayloadSchema.extend({
  hook_event_name: z.literal("UserPromptSubmit"),
  prompt: z.string()
}).loose();

const PreToolPayloadSchema = CommonPayloadSchema.extend({
  hook_event_name: z.literal("PreToolUse"),
  tool_name: z.string().optional(),
  tool_use_id: z.string().optional(),
  tool_input: z.unknown()
}).loose();

const PostToolPayloadSchema = CommonPayloadSchema.extend({
  hook_event_name: z.literal("PostToolUse"),
  tool_name: z.string().optional(),
  tool_use_id: z.string().optional(),
  tool_input: z.unknown(),
  tool_response: z.unknown()
}).loose();

const StopPayloadSchema = CommonPayloadSchema.extend({
  hook_event_name: z.literal("Stop"),
  last_assistant_message: z.string().nullable().optional(),
  stop_hook_active: z.boolean().optional()
}).loose();

export type GitSnapshot = z.infer<typeof GitSnapshotSchema>;

export type EvidenceRef = {
  sessionId: string | null;
  line: number;
  eventName: string | null;
  capturedAt: string;
  sourcePath: string;
};

type NormalizedEventBase = {
  cwd: string | null;
  model: string | null;
  turnId: string | null;
  evidence: EvidenceRef;
};

export type NormalizedEvent =
  | (NormalizedEventBase & {
      type: "session_start";
      source: string | null;
      git: GitSnapshot | null;
    })
  | (NormalizedEventBase & {
      type: "user_prompt";
      prompt: string;
    })
  | (NormalizedEventBase & {
      type: "tool_attempt";
      toolName: string | null;
      toolUseId: string | null;
      input: unknown;
    })
  | (NormalizedEventBase & {
      type: "tool_result";
      toolName: string | null;
      toolUseId: string | null;
      input: unknown;
      response: unknown;
    })
  | (NormalizedEventBase & {
      type: "turn_stop";
      lastAssistantMessage: string | null;
      stopHookActive: boolean | null;
      git: GitSnapshot | null;
    })
  | (NormalizedEventBase & {
      type: "unknown";
      eventName: string | null;
    });

export type AdapterDiagnostic = {
  line: number;
  message: string;
};

export type NormalizedSession = {
  schemaVersion: 1;
  sessionId: string | null;
  sourcePath: string;
  firstObservedAt: string | null;
  lastObservedAt: string | null;
  cwd: string | null;
  model: string | null;
  events: NormalizedEvent[];
  diagnostics: AdapterDiagnostic[];
};

export function readCodexSessionFile(filePath: string): NormalizedSession {
  const canonicalPath = realpathSync(filePath);
  return normalizeCodexSession(readFileSync(canonicalPath, "utf8"), canonicalPath);
}

export function normalizeCodexSession(
  jsonl: string,
  sourcePath: string
): NormalizedSession {
  const events: NormalizedEvent[] = [];
  const diagnostics: AdapterDiagnostic[] = [];
  let sessionId: string | null = null;
  let cwd: string | null = null;
  let model: string | null = null;

  for (const [index, line] of jsonl.split(/\r?\n/).entries()) {
    const lineNumber = index + 1;
    if (line.trim() === "") {
      continue;
    }

    let decoded: unknown;
    try {
      decoded = JSON.parse(line);
    } catch (error) {
      diagnostics.push({ line: lineNumber, message: `Invalid JSON: ${message(error)}` });
      continue;
    }

    const parsedRecord = CapturedRecordSchema.safeParse(decoded);
    if (!parsedRecord.success) {
      diagnostics.push({
        line: lineNumber,
        message: parsedRecord.error.issues
          .map((issue) => `${issue.path.join(".") || "record"}: ${issue.message}`)
          .join("; ")
      });
      continue;
    }

    const record = parsedRecord.data;
    const common = CommonPayloadSchema.safeParse(record.payload);
    const payloadSessionId = common.success ? common.data.session_id ?? null : null;
    const recordSessionId = record.capture.sessionId ?? payloadSessionId;

    if (sessionId === null) {
      sessionId = recordSessionId;
    } else if (recordSessionId !== null && recordSessionId !== sessionId) {
      diagnostics.push({
        line: lineNumber,
        message: `Conflicting session id ${recordSessionId}; expected ${sessionId}`
      });
    }

    if (common.success) {
      cwd ??= common.data.cwd ?? null;
      model ??= common.data.model ?? null;
    }

    const evidence: EvidenceRef = {
      sessionId: recordSessionId,
      line: lineNumber,
      eventName: record.capture.eventName,
      capturedAt: record.capture.capturedAt,
      sourcePath
    };
    events.push(normalizeEvent(record.payload, record.capture.git ?? null, evidence, diagnostics));
  }

  return {
    schemaVersion: 1,
    sessionId,
    sourcePath,
    firstObservedAt: events[0]?.evidence.capturedAt ?? null,
    lastObservedAt: events.at(-1)?.evidence.capturedAt ?? null,
    cwd,
    model,
    events,
    diagnostics
  };
}

function normalizeEvent(
  payload: unknown,
  git: GitSnapshot | null,
  evidence: EvidenceRef,
  diagnostics: AdapterDiagnostic[]
): NormalizedEvent {
  const common = CommonPayloadSchema.safeParse(payload);
  const base: NormalizedEventBase = {
    cwd: common.success ? common.data.cwd ?? null : null,
    model: common.success ? common.data.model ?? null : null,
    turnId: common.success ? common.data.turn_id ?? null : null,
    evidence
  };
  const eventName = common.success
    ? common.data.hook_event_name ?? evidence.eventName
    : evidence.eventName;

  switch (eventName) {
    case "SessionStart": {
      const parsed = SessionStartPayloadSchema.safeParse(payload);
      if (parsed.success) {
        return { ...base, type: "session_start", source: parsed.data.source ?? null, git };
      }
      break;
    }
    case "UserPromptSubmit": {
      const parsed = UserPromptPayloadSchema.safeParse(payload);
      if (parsed.success) {
        return { ...base, type: "user_prompt", prompt: parsed.data.prompt };
      }
      break;
    }
    case "PreToolUse": {
      const parsed = PreToolPayloadSchema.safeParse(payload);
      if (parsed.success) {
        return {
          ...base,
          type: "tool_attempt",
          toolName: parsed.data.tool_name ?? null,
          toolUseId: parsed.data.tool_use_id ?? null,
          input: parsed.data.tool_input
        };
      }
      break;
    }
    case "PostToolUse": {
      const parsed = PostToolPayloadSchema.safeParse(payload);
      if (parsed.success) {
        return {
          ...base,
          type: "tool_result",
          toolName: parsed.data.tool_name ?? null,
          toolUseId: parsed.data.tool_use_id ?? null,
          input: parsed.data.tool_input,
          response: parsed.data.tool_response
        };
      }
      break;
    }
    case "Stop": {
      const parsed = StopPayloadSchema.safeParse(payload);
      if (parsed.success) {
        return {
          ...base,
          type: "turn_stop",
          lastAssistantMessage: parsed.data.last_assistant_message ?? null,
          stopHookActive: parsed.data.stop_hook_active ?? null,
          git
        };
      }
      break;
    }
  }

  diagnostics.push({
    line: evidence.line,
    message: `Could not normalize ${eventName ?? "unknown event"}`
  });
  return { ...base, type: "unknown", eventName };
}

function message(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}
import { z } from "zod";
import type { GitSnapshot, NormalizedSession } from "./codex-session-adapter.ts";
import { SourceClassSchema, type SourceClass } from "./analysis-definitions.ts";
import { redactJson, redactText } from "./redaction.ts";
import { truncateHead, truncateHeadTail, utf8ByteLength } from "./truncation.ts";

export const PROVIDER_REQUEST_BUDGET_BYTES = 512 * 1024;
/** @deprecated Use PROVIDER_REQUEST_BUDGET_BYTES. */
export const BUNDLE_MAX_BYTES = PROVIDER_REQUEST_BUDGET_BYTES;
export const MESSAGE_MAX_BYTES = 2 * 1024;
export const TOOL_INPUT_MAX_BYTES = 1 * 1024;
export const TOOL_OUTPUT_HEAD_BYTES = 700;
export const TOOL_OUTPUT_TAIL_BYTES = 300;
export const GIT_STATUS_MAX_BYTES = 2 * 1024;
export const GIT_DIFF_HEAD_BYTES = 3 * 1024;
export const GIT_DIFF_TAIL_BYTES = 1 * 1024;

const ErrorIndicatorSchema = z
  .object({
    field: z.string(),
    value: z.union([z.string(), z.number(), z.boolean()])
  })
  .strict();

const StructuralFactsSchema = z
  .object({
    sequence: z.number().int().positive(),
    toolUseId: z.string().nullable().optional(),
    matchedEvidenceId: z.string().optional(),
    errorIndicators: z.array(ErrorIndicatorSchema).optional(),
    promptOrdinal: z.number().int().positive().optional(),
    assistantMessageOrdinal: z.number().int().positive().optional()
  })
  .strict();

const EvidenceItemSchema = z
  .object({
    id: z.string().regex(/^E[1-9]\d*(?:\.git)?$/),
    sourceClass: SourceClassSchema,
    timestamp: z.string().min(1),
    turnId: z.string().nullable(),
    content: z.unknown(),
    structuralFacts: StructuralFactsSchema
  })
  .strict();

export const EvidenceBundleSchema = z
  .object({
    schemaVersion: z.literal(1),
    session: z
      .object({
        sessionId: z.string().nullable(),
        firstObservedAt: z.string().nullable(),
        lastObservedAt: z.string().nullable(),
        cwd: z.string().nullable(),
        model: z.string().nullable()
      })
      .strict(),
    evidence: z.array(EvidenceItemSchema),
    diagnostics: z.array(z.string())
  })
  .strict()
  .superRefine((bundle, context) => {
    const seenIds = new Set<string>();
    bundle.evidence.forEach((item, index) => {
      if (seenIds.has(item.id)) {
        context.addIssue({
          code: "custom",
          path: ["evidence", index, "id"],
          message: `Duplicate evidence id ${item.id}`
        });
      }
      seenIds.add(item.id);
      if (item.structuralFacts.sequence !== index + 1) {
        context.addIssue({
          code: "custom",
          path: ["evidence", index, "structuralFacts", "sequence"],
          message: "Evidence sequence must match ordered bundle position"
        });
      }
    });
  });

export type EvidenceBundle = z.infer<typeof EvidenceBundleSchema>;
export type EvidenceItem = z.infer<typeof EvidenceItemSchema>;
export type EvidenceCorpusStatus = {
  serializedCorpusBytes: number;
  requestBudgetBytes: number;
  totalEvidenceCount: number;
  retainedEvidenceCount: number;
  omittedEvidenceCount: number;
  eligibleForSingleRequest: boolean;
};

export function buildEvidenceBundle(session: NormalizedSession): EvidenceBundle {
  const evidence: EvidenceItem[] = [];
  const attemptsByToolUseId = new Map<string, string>();
  let promptOrdinal = 0;
  let assistantMessageOrdinal = 0;

  const append = (
    item: Omit<EvidenceItem, "structuralFacts"> & {
      structuralFacts?: Omit<EvidenceItem["structuralFacts"], "sequence">;
    }
  ): void => {
    evidence.push({
      ...item,
      structuralFacts: { sequence: evidence.length + 1, ...item.structuralFacts }
    });
  };

  for (const event of session.events) {
    const id = `E${event.evidence.line}`;
    const common = {
      timestamp: event.evidence.capturedAt,
      turnId: event.turnId
    };

    switch (event.type) {
      case "session_start":
        append({
          id,
          sourceClass: "session_event",
          ...common,
          content: { event: "session_start", source: redactNullable(event.source) }
        });
        if (event.git !== null) {
          appendGit(append, `${id}.git`, common, event.git);
        }
        break;
      case "user_prompt":
        promptOrdinal += 1;
        append({
          id,
          sourceClass: "human_message",
          ...common,
          content: truncateHead(redactText(event.prompt), MESSAGE_MAX_BYTES),
          structuralFacts: { promptOrdinal }
        });
        break;
      case "tool_attempt":
        append({
          id,
          sourceClass: "tool_attempt",
          ...common,
          content: {
            toolName: redactNullable(event.toolName),
            input: truncateHead(redactJson(event.input), TOOL_INPUT_MAX_BYTES)
          },
          structuralFacts: { toolUseId: redactNullable(event.toolUseId) }
        });
        if (event.toolUseId !== null) {
          attemptsByToolUseId.set(event.toolUseId, id);
        }
        break;
      case "tool_result": {
        const matchedEvidenceId =
          event.toolUseId === null ? undefined : attemptsByToolUseId.get(event.toolUseId);
        append({
          id,
          sourceClass: "tool_result",
          ...common,
          content: {
            toolName: redactNullable(event.toolName),
            input: truncateHead(redactJson(event.input), TOOL_INPUT_MAX_BYTES),
            output: truncateHeadTail(
              redactJson(event.response),
              TOOL_OUTPUT_HEAD_BYTES,
              TOOL_OUTPUT_TAIL_BYTES
            )
          },
          structuralFacts: {
            toolUseId: redactNullable(event.toolUseId),
            ...(matchedEvidenceId ? { matchedEvidenceId } : {}),
            errorIndicators: structuredErrorIndicators(event.response)
          }
        });
        break;
      }
      case "turn_stop":
        assistantMessageOrdinal += 1;
        append({
          id,
          sourceClass: "assistant_message",
          ...common,
          content:
            event.lastAssistantMessage === null
              ? null
              : truncateHead(
                  redactText(event.lastAssistantMessage),
                  MESSAGE_MAX_BYTES
                ),
          structuralFacts: { assistantMessageOrdinal }
        });
        if (event.git !== null) {
          appendGit(append, `${id}.git`, common, event.git);
        }
        break;
      case "unknown":
        break;
    }
  }

  const diagnostics = session.diagnostics.map((diagnostic) =>
    truncateHead(
      redactText(`Line ${diagnostic.line}: ${diagnostic.message}`),
      MESSAGE_MAX_BYTES
    )
  );
  const bundle: EvidenceBundle = {
    schemaVersion: 1,
    session: {
      sessionId: truncateNullable(session.sessionId, 512),
      firstObservedAt: truncateNullable(session.firstObservedAt, 256),
      lastObservedAt: truncateNullable(session.lastObservedAt, 256),
      cwd: truncateNullable(session.cwd, MESSAGE_MAX_BYTES),
      model: truncateNullable(session.model, MESSAGE_MAX_BYTES)
    },
    evidence,
    diagnostics
  };

  return EvidenceBundleSchema.parse(bundle);
}

export function measureEvidenceCorpus(
  bundle: EvidenceBundle,
  requestBudgetBytes: number = PROVIDER_REQUEST_BUDGET_BYTES
): EvidenceCorpusStatus {
  const serializedCorpusBytes = serializedBytes(bundle);
  const totalEvidenceCount = bundle.evidence.length;
  return {
    serializedCorpusBytes,
    requestBudgetBytes,
    totalEvidenceCount,
    retainedEvidenceCount: totalEvidenceCount,
    omittedEvidenceCount: 0,
    eligibleForSingleRequest: serializedCorpusBytes <= requestBudgetBytes
  };
}

function appendGit(
  append: (
    item: Omit<EvidenceItem, "structuralFacts"> & {
      structuralFacts?: Omit<EvidenceItem["structuralFacts"], "sequence">;
    }
  ) => void,
  id: string,
  common: { timestamp: string; turnId: string | null },
  git: GitSnapshot
): void {
  append({
    id,
    sourceClass: "git_snapshot",
    ...common,
    content: {
      head: redactNullable(git.head),
      branch: redactNullable(git.branch),
      status:
        git.status === null
          ? null
          : truncateHead(redactText(git.status), GIT_STATUS_MAX_BYTES),
      diff:
        git.diff === null
          ? null
          : truncateHeadTail(
              redactText(git.diff),
              GIT_DIFF_HEAD_BYTES,
              GIT_DIFF_TAIL_BYTES
            ),
      errors: git.errors.map(redactText)
    }
  });
}

function structuredErrorIndicators(
  response: unknown
): Array<{ field: string; value: string | number | boolean }> {
  if (!isRecord(response)) {
    return [];
  }

  const indicators: Array<{ field: string; value: string | number | boolean }> = [];
  if (response.success === false) {
    indicators.push({ field: "success", value: false });
  }
  if (response.isError === true) {
    indicators.push({ field: "isError", value: true });
  }
  if (response.is_error === true) {
    indicators.push({ field: "is_error", value: true });
  }
  for (const field of ["exitCode", "exit_code"] as const) {
    const value = response[field];
    if (typeof value === "number" && value !== 0) {
      indicators.push({ field, value });
    }
  }
  if (typeof response.error === "string" && response.error.trim() !== "") {
    indicators.push({ field: "error", value: truncateHead(redactText(response.error), 256) });
  }
  return indicators;
}

function serializedBytes(bundle: EvidenceBundle): number {
  return utf8ByteLength(`${JSON.stringify(bundle, null, 2)}\n`);
}

function redactNullable(value: string | null): string | null {
  return value === null ? null : redactText(value);
}

function truncateNullable(value: string | null, maximumBytes: number): string | null {
  return value === null
    ? null
    : truncateHead(redactText(value), maximumBytes);
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

