  "substantial_structural_investigation"
] as const;
export const ACTIVITY_ONLY_REASONS = [
  "insufficient_structural_evidence"
] as const;
export const BLOCKED_REASONS = [
  "bundle_too_large",
  "automatic_analysis_not_enabled",
  "missing_api_key"
] as const;
export const FULL_REPORT_REASONS = ["validated_analysis_available"] as const;
export const ANALYSIS_FAILURE_REASONS = [
  "request_failed",
  "refusal",
  "incomplete",
  "missing_parsed_output",
  "schema_invalid",
  "validation_failed",
  "report_generation_failed",
  "analysis_artifact_persistence_failed"
] as const;

export const AutomaticAnalyzeReasonSchema = z.enum(AUTOMATIC_ANALYZE_REASONS);
export const ActivityOnlyReasonSchema = z.enum(ACTIVITY_ONLY_REASONS);
export const BlockedReasonSchema = z.enum(BLOCKED_REASONS);
export const FullReportReasonSchema = z.enum(FULL_REPORT_REASONS);
export const AnalysisFailureReasonSchema = z.enum(ANALYSIS_FAILURE_REASONS);

export const SafeAnalysisRunIdSchema = z
  .string()
  .regex(/^[A-Za-z0-9][A-Za-z0-9._-]{0,255}$/, "Invalid analysis run id");

export const EvidenceCorpusStatusSchema = z
  .object({
    serializedCorpusBytes: z.number().int().nonnegative(),
    requestBudgetBytes: z.number().int().nonnegative(),
    totalEvidenceCount: z.number().int().nonnegative(),
    retainedEvidenceCount: z.number().int().nonnegative(),
    omittedEvidenceCount: z.number().int().nonnegative(),
    eligibleForSingleRequest: z.boolean()
  })
  .strict();

const ReceiptCountsSchema = z
  .object({
    humanMessages: z.number().int().nonnegative(),
    assistantMessages: z.number().int().nonnegative(),
    toolAttempts: z.number().int().nonnegative(),
    toolResults: z.number().int().nonnegative(),
    gitSnapshots: z.number().int().nonnegative(),
    matchedToolResults: z.number().int().nonnegative(),
    observableStructuredErrorResults: z.number().int().nonnegative(),
    distinctTurns: z.number().int().nonnegative()
  })
  .strict();

const CHANGED_SNAPSHOT_RESULT_DESCRIPTION =
  "Counts matched tool results occurring between consecutive Git snapshots whose observable Git state differs. This demonstrates result activity during the observed change window; it does not prove verification or that the result occurred after the repository change.";

export const StructuralSessionReceiptSchema = z
  .object({
    sessionId: z.string().nullable(),
    evidenceStateHash: z.string().regex(/^[a-f0-9]{64}$/),
    evaluatedAt: z.string().datetime({ offset: true }),
    lastObservedActivityAt: z.string().min(1).nullable(),
    corpus: EvidenceCorpusStatusSchema,
    counts: ReceiptCountsSchema,
    gitStateChangedBetweenSnapshots: z.boolean(),
    matchedResultsBetweenChangedSnapshots: z
      .number()
      .int()
      .nonnegative()
      .describe(CHANGED_SNAPSHOT_RESULT_DESCRIPTION),
    hasMatchedResultsBetweenChangedSnapshots: z
      .boolean()
      .describe(CHANGED_SNAPSHOT_RESULT_DESCRIPTION)
  })
  .strict();

const RenderedArtifactsSchema = z
  .object({
    markdown: z.literal("report.md").optional(),
    html: z.literal("report.html").optional()
  })
  .strict()
  .refine((value) => value.markdown !== undefined || value.html !== undefined, {
    message: "At least one rendered artifact must be referenced"
  });

export const ValidatedRunReferenceSchema = z
  .object({
    runId: SafeAnalysisRunIdSchema,
    analysisArtifact: z.literal("analysis.json"),
    validationSummaryArtifact: z.literal("validation-summary.json"),
    renderedArtifacts: RenderedArtifactsSchema.optional()
  })
  .strict();

export const AnalysisRunReferenceSchema = z
  .object({ runId: SafeAnalysisRunIdSchema })
  .strict();

const DispositionSchemaVersion = z
  .literal(1)
  .describe(
    "Schema version for the complete persisted disposition document, including its nested structural receipt."
  );

export const ActivityOnlyDispositionSchema = z
  .object({
    schemaVersion: DispositionSchemaVersion,
    kind: z.literal("activity_only"),
    reason: ActivityOnlyReasonSchema,
    receipt: StructuralSessionReceiptSchema
  })
  .strict();

export const BlockedDispositionSchema = z
  .object({
    schemaVersion: DispositionSchemaVersion,
    kind: z.literal("blocked"),
    reason: BlockedReasonSchema,
    receipt: StructuralSessionReceiptSchema
  })
  .strict();

export const FullReportDispositionSchema = z
  .object({
    schemaVersion: DispositionSchemaVersion,
    kind: z.literal("full_report"),
    reason: FullReportReasonSchema,
    receipt: StructuralSessionReceiptSchema,
    validatedRun: ValidatedRunReferenceSchema
  })
  .strict();

export const AnalysisFailedDispositionSchema = z
  .object({
    schemaVersion: DispositionSchemaVersion,
    kind: z.literal("analysis_failed"),
    reason: AnalysisFailureReasonSchema,
    receipt: StructuralSessionReceiptSchema,
    analysisRun: AnalysisRunReferenceSchema.optional()
  })
  .strict();

export const FinalSessionDispositionSchema = z
  .discriminatedUnion("kind", [
    FullReportDispositionSchema,
    ActivityOnlyDispositionSchema,
    BlockedDispositionSchema,
    AnalysisFailedDispositionSchema
  ])
  .describe(
    "Latest final session disposition. Its outer schemaVersion governs the entire document, including the nested receipt."
  );

export const AutomaticAnalysisEnvironmentSchema = z
  .object({
    automaticAnalysisEnabled: z.boolean(),
    apiKeyAvailable: z.boolean()
  })
  .strict();

export const AutomaticAnalysisDecisionSchema = z.discriminatedUnion("kind", [
  z
    .object({
      kind: z.literal("analyze"),
      reason: AutomaticAnalyzeReasonSchema,
      receipt: StructuralSessionReceiptSchema
    })
    .strict(),
  z
    .object({
      kind: z.literal("activity_only"),
      reason: ActivityOnlyReasonSchema,
      receipt: StructuralSessionReceiptSchema
    })
    .strict(),
  z
    .object({
      kind: z.literal("blocked"),
      reason: BlockedReasonSchema,
      receipt: StructuralSessionReceiptSchema
    })
    .strict()
]);

export type StructuralSessionReceipt = z.infer<
  typeof StructuralSessionReceiptSchema
>;
export type AutomaticAnalysisEnvironment = z.infer<
  typeof AutomaticAnalysisEnvironmentSchema
>;
export type AutomaticAnalysisDecision = z.infer<
  typeof AutomaticAnalysisDecisionSchema
>;
export type FinalSessionDisposition = z.infer<
  typeof FinalSessionDispositionSchema
>;
export type ActivityOnlyDisposition = z.infer<
  typeof ActivityOnlyDispositionSchema
>;
export type BlockedDisposition = z.infer<typeof BlockedDispositionSchema>;
export type FullReportDisposition = z.infer<
  typeof FullReportDispositionSchema
>;
export type AnalysisFailedDisposition = z.infer<
  typeof AnalysisFailedDispositionSchema
>;
export type ValidatedRunReference = z.infer<
  typeof ValidatedRunReferenceSchema
>;
export type AnalysisFailureReason = z.infer<typeof AnalysisFailureReasonSchema>;
export type StructuralAutomaticAnalysisDecision =
  | Extract<AutomaticAnalysisDecision, { kind: "activity_only" | "blocked" }>
  | {
      kind: "eligible";
      reason: z.infer<typeof AutomaticAnalyzeReasonSchema>;
      receipt: StructuralSessionReceipt;
    };

export function assessAutomaticAnalysis(options: {
  bundle: EvidenceBundle;
  corpusStatus: EvidenceCorpusStatus;
  environment: AutomaticAnalysisEnvironment;
  evaluatedAt: string;
}): AutomaticAnalysisDecision {
  const structuralDecision = assessAutomaticAnalysisStructure(options);
  if (structuralDecision.kind !== "eligible") {
    return AutomaticAnalysisDecisionSchema.parse(structuralDecision);
  }
  const environment = AutomaticAnalysisEnvironmentSchema.parse(
    options.environment
  );
  if (!environment.automaticAnalysisEnabled) {
    return AutomaticAnalysisDecisionSchema.parse({
      kind: "blocked",
      reason: "automatic_analysis_not_enabled",
      receipt: structuralDecision.receipt
    });
  }
  if (!environment.apiKeyAvailable) {
    return AutomaticAnalysisDecisionSchema.parse({
      kind: "blocked",
      reason: "missing_api_key",
      receipt: structuralDecision.receipt
    });
  }
  return AutomaticAnalysisDecisionSchema.parse({
    kind: "analyze",
    reason: structuralDecision.reason,
    receipt: structuralDecision.receipt
  });
}

export function assessAutomaticAnalysisStructure(options: {
  bundle: EvidenceBundle;
  corpusStatus: EvidenceCorpusStatus;
  evaluatedAt: string;
}): StructuralAutomaticAnalysisDecision {
  const bundle = EvidenceBundleSchema.parse(options.bundle);
  const corpusStatus = validateCorpusStatus(bundle, options.corpusStatus);
  const receipt = buildStructuralSessionReceipt(
    bundle,
    corpusStatus,
    options.evaluatedAt
  );
  const eligibilityReason = structuralEligibilityReason(receipt);

  if (eligibilityReason === null) {
    const decision = AutomaticAnalysisDecisionSchema.parse({
      kind: "activity_only",
      reason: "insufficient_structural_evidence",
      receipt
    });
    if (decision.kind !== "activity_only") {
      throw new Error("Structural activity decision parsed inconsistently");
    }
    return decision;
  }
  if (!corpusStatus.eligibleForSingleRequest) {
    const decision = AutomaticAnalysisDecisionSchema.parse({
      kind: "blocked",
      reason: "bundle_too_large",
      receipt
    });
    if (decision.kind !== "blocked") {
      throw new Error("Structural blocked decision parsed inconsistently");
    }
    return decision;
  }
  return {
    kind: "eligible",
    reason: eligibilityReason,
    receipt
  };
}

export function buildStructuralSessionReceipt(
  bundleInput: EvidenceBundle,
  corpusStatusInput: EvidenceCorpusStatus,
  evaluatedAt: string
): StructuralSessionReceipt {
  const bundle = EvidenceBundleSchema.parse(bundleInput);
  const corpusStatus = validateCorpusStatus(bundle, corpusStatusInput);
  const sourceCounts = countSourceClasses(bundle.evidence);
  const matchedResultIds = matchedToolResultIds(bundle.evidence);
  const intervalFacts = changedSnapshotIntervalFacts(
    bundle.evidence,
    matchedResultIds
  );

  return StructuralSessionReceiptSchema.parse({
    sessionId: bundle.session.sessionId,
    evidenceStateHash: computeEvidenceStateHash(bundle),
    evaluatedAt,
    lastObservedActivityAt: bundle.session.lastObservedAt,
    corpus: corpusStatus,
    counts: {
      humanMessages: sourceCounts.human_message,
      assistantMessages: sourceCounts.assistant_message,
      toolAttempts: sourceCounts.tool_attempt,
      toolResults: sourceCounts.tool_result,
      gitSnapshots: sourceCounts.git_snapshot,
      matchedToolResults: matchedResultIds.size,
      observableStructuredErrorResults: bundle.evidence.filter(
        (item) =>
          item.sourceClass === "tool_result" &&
          (item.structuralFacts.errorIndicators?.length ?? 0) > 0
      ).length,
      distinctTurns: new Set(
        bundle.evidence.flatMap((item) =>
          item.turnId === null ? [] : [item.turnId]
        )
      ).size
    },
    ...intervalFacts
  });
}

export function computeEvidenceStateHash(bundleInput: EvidenceBundle): string {
  const bundle = EvidenceBundleSchema.parse(bundleInput);
  const projection = {
    schemaVersion: bundle.schemaVersion,
    session: {
      sessionId: bundle.session.sessionId,
      firstObservedAt: bundle.session.firstObservedAt,
      lastObservedAt: bundle.session.lastObservedAt,
      cwd: bundle.session.cwd,
      model: bundle.session.model
    },
    evidence: bundle.evidence.map((item) => ({
      id: item.id,
      sourceClass: item.sourceClass,
      timestamp: item.timestamp,
      turnId: item.turnId,
      content: item.content,
      structuralFacts: projectStructuralFacts(item)
    }))
  };

  // EvidenceBundle diagnostics are currently display strings, not structured
  // stable diagnostic fields. They are deliberately excluded until the bundle
  // exposes a structured captured-evidence diagnostic schema.
  return createHash("sha256")
    .update(canonicalJson(projection), "utf8")
    .digest("hex");
}

export function finalDispositionFromDecision(
  decisionInput: Exclude<AutomaticAnalysisDecision, { kind: "analyze" }>
): ActivityOnlyDisposition | BlockedDisposition {
  const decision = AutomaticAnalysisDecisionSchema.parse(decisionInput);
  if (decision.kind === "analyze") {
    throw new Error("An analyze decision is not a final session disposition");
  }
  if (decision.kind === "activity_only") {
    return ActivityOnlyDispositionSchema.parse({
      schemaVersion: 1,
      kind: decision.kind,
      reason: decision.reason,
      receipt: decision.receipt
    });
  }
  return BlockedDispositionSchema.parse({
    schemaVersion: 1,
    kind: decision.kind,
    reason: decision.reason,
    receipt: decision.receipt
  });
}

export function createFullReportDisposition(
  receipt: StructuralSessionReceipt,
  validatedRun: ValidatedRunReference
): FullReportDisposition {
  return FullReportDispositionSchema.parse({
    schemaVersion: 1,
    kind: "full_report",
    reason: "validated_analysis_available",
    receipt,
    validatedRun
  });
}

export function createAnalysisFailedDisposition(
  receipt: StructuralSessionReceipt,
  reason: AnalysisFailureReason,
  analysisRun?: z.input<typeof AnalysisRunReferenceSchema>
): AnalysisFailedDisposition {
  return AnalysisFailedDispositionSchema.parse({
    schemaVersion: 1,
    kind: "analysis_failed",
    reason,
    receipt,
    ...(analysisRun === undefined ? {} : { analysisRun })
  });
}

function validateCorpusStatus(
  bundle: EvidenceBundle,
  statusInput: EvidenceCorpusStatus
): EvidenceCorpusStatus {
  const status = EvidenceCorpusStatusSchema.parse(statusInput);
  const measured = measureEvidenceCorpus(bundle, status.requestBudgetBytes);
  if (JSON.stringify(status) !== JSON.stringify(measured)) {
    throw new Error("Evidence corpus status does not match the sanitized bundle");
  }
  return status;
}

function structuralEligibilityReason(
  receipt: StructuralSessionReceipt
): z.infer<typeof AutomaticAnalyzeReasonSchema> | null {
  const thresholds = SESSION_ELIGIBILITY_THRESHOLDS;
  if (
    receipt.matchedResultsBetweenChangedSnapshots >=
    thresholds.minimumMatchedResultsBetweenChangedSnapshots
  ) {
    return "git_change_with_result_activity";
  }
  if (
    receipt.counts.humanMessages >=
      thresholds.minimumHumanMessagesForInvestigation &&
    receipt.counts.distinctTurns >=
      thresholds.minimumDistinctTurnsForInvestigation &&
    receipt.counts.matchedToolResults >=
      thresholds.minimumMatchedToolResultsForInvestigation &&
    receipt.counts.observableStructuredErrorResults >=
      thresholds.minimumObservableErrorResultsForInvestigation
  ) {
    return "substantial_structural_investigation";
  }
  return null;
}

function countSourceClasses(evidence: EvidenceBundle["evidence"]): Record<
  EvidenceItem["sourceClass"],
  number
> {
  const counts: Record<EvidenceItem["sourceClass"], number> = {
    session_event: 0,
    human_message: 0,
    assistant_message: 0,
    tool_attempt: 0,
    tool_result: 0,
    git_snapshot: 0
  };
  for (const item of evidence) {
    counts[item.sourceClass] += 1;
  }
  return counts;
}

function matchedToolResultIds(
  evidence: EvidenceBundle["evidence"]
): Set<string> {
  const attempts = new Map(
    evidence
      .filter((item) => item.sourceClass === "tool_attempt")
      .map((item) => [item.id, item.structuralFacts.sequence])
  );
  return new Set(
    evidence.flatMap((item) => {
      if (item.sourceClass !== "tool_result") return [];
      const matchedId = item.structuralFacts.matchedEvidenceId;
      const attemptSequence = matchedId ? attempts.get(matchedId) : undefined;
      return attemptSequence !== undefined &&
        attemptSequence < item.structuralFacts.sequence
        ? [item.id]
        : [];
    })
  );
}

const GitSnapshotContentSchema = z
  .object({
    head: z.string().nullable(),
    branch: z.string().nullable(),
    status: z.string().nullable(),
    diff: z.string().nullable(),
    errors: z.array(z.string())
  })
  .strict();

type ParsedGitSnapshot = {
  sequence: number;
  state: {
    head: string | null;
    branch: string | null;
    status: string | null;
    diff: string | null;
  } | null;
};

function changedSnapshotIntervalFacts(
  evidence: EvidenceBundle["evidence"],
  matchedResultIds: ReadonlySet<string>
): Pick<
  StructuralSessionReceipt,
  | "gitStateChangedBetweenSnapshots"
  | "matchedResultsBetweenChangedSnapshots"
  | "hasMatchedResultsBetweenChangedSnapshots"
> {
  const snapshots: ParsedGitSnapshot[] = evidence
    .filter((item) => item.sourceClass === "git_snapshot")
    .map((item) => {
      const parsed = GitSnapshotContentSchema.safeParse(item.content);
      return {
        sequence: item.structuralFacts.sequence,
        state: parsed.success
          ? {
              head: parsed.data.head,
              branch: parsed.data.branch,
              status: parsed.data.status,
              diff: parsed.data.diff
            }
          : null
      };
    });
  const resultsInChangedIntervals = new Set<string>();
  let gitStateChangedBetweenSnapshots = false;

  // Counts matched tool results occurring between consecutive Git snapshots
  // whose observable Git state differs. This demonstrates result activity
  // during the observed change window; it does not prove verification or that
  // the result occurred after the repository change.
  for (let index = 1; index < snapshots.length; index += 1) {
    const before = snapshots[index - 1];
    const after = snapshots[index];
    if (
      before === undefined ||
      after === undefined ||
      before.state === null ||
      after.state === null ||
      canonicalJson(before.state) === canonicalJson(after.state)
    ) {
      continue;
    }
    gitStateChangedBetweenSnapshots = true;
    for (const item of evidence) {
      if (
        matchedResultIds.has(item.id) &&
        item.structuralFacts.sequence > before.sequence &&
        item.structuralFacts.sequence <= after.sequence
      ) {
        resultsInChangedIntervals.add(item.id);
      }
    }
  }

  const matchedResultsBetweenChangedSnapshots =
    resultsInChangedIntervals.size;
  return {
    gitStateChangedBetweenSnapshots,
    matchedResultsBetweenChangedSnapshots,
    hasMatchedResultsBetweenChangedSnapshots:
      matchedResultsBetweenChangedSnapshots > 0
  };
}

function projectStructuralFacts(item: EvidenceItem): Record<string, unknown> {
  const projected: Record<string, unknown> = {
    sequence: item.structuralFacts.sequence
  };
  for (const field of [
    "toolUseId",
    "matchedEvidenceId",
    "errorIndicators",
    "promptOrdinal",
    "assistantMessageOrdinal"
  ] as const) {
    const value = item.structuralFacts[field];
    if (value !== undefined) projected[field] = value;
  }
  return projected;
}

function canonicalJson(value: unknown): string {
  if (value === null || typeof value === "boolean" || typeof value === "string") {
    return JSON.stringify(value);
  }
  if (typeof value === "number") {
    if (!Number.isFinite(value)) throw new Error("Canonical JSON requires finite numbers");
    return JSON.stringify(value);
  }
  if (Array.isArray(value)) {
    return `[${value.map((entry) => canonicalJson(entry)).join(",")}]`;
  }
  if (typeof value === "object") {
    const entries = Object.entries(value as Record<string, unknown>)
      .filter(([, entry]) => entry !== undefined)
      .sort(([left], [right]) => left.localeCompare(right));
    return `{${entries
      .map(([key, entry]) => `${JSON.stringify(key)}:${canonicalJson(entry)}`)
      .join(",")}}`;
  }
  throw new Error(`Canonical JSON cannot represent ${typeof value}`);
}

import { z } from "zod";
import {
  ACTIVITY_SOURCE_CLASSES,
  AnalysisSchema,
  CandidateAnalysisSchema,
  CODEX_CONTRIBUTION_SOURCE_CLASSES,
  EXPLICIT_SOURCE_CLASSES,
  formatSourceClasses,
  HUMAN_INTERVENTION_SOURCE_CLASSES,
  OBSERVED_SOURCE_CLASSES,
  REPORTED_OUTCOME_SOURCE_CLASSES,
  RESULT_BEARING_OUTCOME_SOURCE_CLASSES,
  TOOL_ATTEMPT_SOURCE_CLASSES,
  unknownFinding,
  type Analysis,
  type CandidateAnalysis,
  type CandidateFinding,
  type EvidenceBasis,
  type SourceClass
} from "./analysis-definitions.ts";
import type { EvidenceBundle, EvidenceItem } from "./evidence-bundle.ts";

export const VALIDATION_ACTION_CODES = [
  "turning_point_citations_completed",
  "outcome_support_attempt_only_to_reported_only",
  "outcome_support_attempt_only_to_unknown"
] as const;

export type ValidationActionCode = (typeof VALIDATION_ACTION_CODES)[number];

export const ValidationActionSchema = z
  .object({
    action: z.enum(["rejected", "downgraded", "amended"]),
    code: z.enum(VALIDATION_ACTION_CODES).optional(),
    target: z.string().min(1),
    reason: z.string().min(1),
    evidenceIds: z.array(z.string())
  })
  .strict();

export const ValidationSummarySchema = z
  .object({
    schemaVersion: z.literal(1),
    runId: z.string().min(1),
    validatedAt: z.string().min(1),
    rejectedCount: z.number().int().nonnegative(),
    downgradedCount: z.number().int().nonnegative(),
    amendedCount: z.number().int().nonnegative().default(0),
    actions: z.array(ValidationActionSchema)
  })
  .strict();

export type ValidationSummary = z.infer<typeof ValidationSummarySchema>;
export type ValidationResult = {
  analysis: Analysis;
  summary: ValidationSummary;
};

type FindingOptions = {
  allowedSourceClasses?: ReadonlySet<SourceClass>;
  requiredBasis?: EvidenceBasis;
  requiresEvidence?: boolean;
  requiresKnownValue?: boolean;
};

export const VALIDATOR_SOURCE_CLASS_POLICIES = {
  observedBasis: OBSERVED_SOURCE_CLASSES,
  explicitBasis: EXPLICIT_SOURCE_CLASSES,
  activityOutcome: ACTIVITY_SOURCE_CLASSES,
  resultBearingOutcome: RESULT_BEARING_OUTCOME_SOURCE_CLASSES,
  codexContribution: CODEX_CONTRIBUTION_SOURCE_CLASSES,
  humanIntervention: HUMAN_INTERVENTION_SOURCE_CLASSES,
  reportedOutcome: REPORTED_OUTCOME_SOURCE_CLASSES
} as const;

const OBSERVED_SOURCES = new Set<SourceClass>(
  VALIDATOR_SOURCE_CLASS_POLICIES.observedBasis
);
const EXPLICIT_SOURCES = new Set<SourceClass>(
  VALIDATOR_SOURCE_CLASS_POLICIES.explicitBasis
);
const ACTIVITY_SOURCES = new Set<SourceClass>(
  VALIDATOR_SOURCE_CLASS_POLICIES.activityOutcome
);
const RESULT_BEARING_OUTCOME_SOURCES = new Set<SourceClass>(
  VALIDATOR_SOURCE_CLASS_POLICIES.resultBearingOutcome
);
const CODEX_CONTRIBUTION_SOURCES = new Set<SourceClass>(
  VALIDATOR_SOURCE_CLASS_POLICIES.codexContribution
);
const HUMAN_INTERVENTION_SOURCES = new Set<SourceClass>(
  VALIDATOR_SOURCE_CLASS_POLICIES.humanIntervention
);
const REPORTED_OUTCOME_SOURCES = new Set<SourceClass>(
  VALIDATOR_SOURCE_CLASS_POLICIES.reportedOutcome
);

export function validateAnalysis(
  candidate: unknown,
  bundle: EvidenceBundle,
  runId: string,
  now: Date = new Date()
): ValidationResult {
  const actions: ValidationSummary["actions"] = [];
  const evidenceById = new Map(bundle.evidence.map((item) => [item.id, item]));
  const evidenceOrder = new Map(
    bundle.evidence.map((item, index) => [item.id, index])
  );
  const parsed = CandidateAnalysisSchema.safeParse(candidate);
  let working: CandidateAnalysis;

  if (!parsed.success) {
    actions.push({
      action: "rejected",
      target: "analysis",
      reason: `Analysis failed structural schema validation: ${parsed.error.issues
        .map((issue) => `${issue.path.join(".") || "analysis"}: ${issue.message}`)
        .join("; ")}`,
      evidenceIds: []
    });
    working = emptyAnalysis();
  } else {
    working = structuredClone(parsed.data);
  }

  const validateFinding = <T extends CandidateFinding>(
    finding: T,
    target: string,
    options: FindingOptions = {}
  ): T | null => {
    const invalidEvidenceIds = finding.evidenceIds.filter(
      (id) => !evidenceById.has(id)
    );
    if (invalidEvidenceIds.length > 0) {
      reject(
        actions,
        target,
        `Finding cites nonexistent evidence: ${invalidEvidenceIds.join(", ")}.`,
        finding.evidenceIds
      );
      return null;
    }

    if (finding.basis !== "unknown" && finding.evidenceIds.length === 0) {
      reject(actions, target, "Non-unknown finding has no evidence citations.", []);
      return null;
    }
    if (options.requiresEvidence && finding.evidenceIds.length === 0) {
      reject(actions, target, "This category requires evidence citations.", []);
      return null;
    }
    if (
      options.requiresKnownValue &&
      (finding.basis === "unknown" || finding.value === null)
    ) {
      reject(
        actions,
        target,
        "This category requires a non-unknown finding value.",
        finding.evidenceIds
      );
      return null;
    }

    const citedItems = finding.evidenceIds
      .map((id) => evidenceById.get(id))
      .filter((item): item is EvidenceItem => item !== undefined);

    if (
      options.allowedSourceClasses &&
      citedItems.some((item) => !options.allowedSourceClasses?.has(item.sourceClass))
    ) {
      reject(
        actions,
        target,
        `Finding cites a source class forbidden for this category; allowed classes are ${[
          ...options.allowedSourceClasses
        ].join(", ")}.`,
        finding.evidenceIds
      );
      return null;
    }

    let validated = { ...finding };
    if (options.requiredBasis && validated.basis !== options.requiredBasis) {
      if (options.requiredBasis === "inference" && validated.evidenceIds.length > 0) {
        validated = downgradeToInference(
          validated,
          target,
          `This category requires basis ${options.requiredBasis}.`,
          actions
        );
      } else {
        reject(
          actions,
          target,
          `This category requires basis ${options.requiredBasis}.`,
          validated.evidenceIds
        );
        return null;
      }
    }

    if (validated.basis === "observed" && !allSourcesAllowed(citedItems, OBSERVED_SOURCES)) {
      validated = downgradeToInference(
        validated,
        target,
        "Observed basis was not supported exclusively by activity or state evidence.",
        actions
      );
    } else if (
      validated.basis === "explicit" &&
      !allSourcesAllowed(citedItems, EXPLICIT_SOURCES)
    ) {
      validated = downgradeToInference(
        validated,
        target,
        "Explicit basis was not supported exclusively by human or assistant messages.",
        actions
      );
    }

    if (validated.basis === "inference") {
      if (
        validated.confidence === undefined ||
        validated.confidenceReason === undefined
      ) {
        validated = {
          ...validated,
          confidence: validated.confidence ?? "low",
          confidenceReason:
            validated.confidenceReason ??
            "Validator supplied low confidence because the candidate omitted inference confidence metadata."
        };
        downgrade(
          actions,
          target,
          "Inference finding omitted confidence or its reason; supplied deterministic low-confidence metadata.",
          validated.evidenceIds
        );
      }
    } else if (
      validated.confidence !== undefined ||
      validated.confidenceReason !== undefined
    ) {
      const { confidence: _confidence, confidenceReason: _reason, ...withoutConfidence } =
        validated;
      validated = withoutConfidence as T;
      downgrade(
        actions,
        target,
        "Removed confidence metadata from a non-inference finding.",
        validated.evidenceIds
      );
    }

    return validated as T;
  };

  const objective = validateFinding(working.objective, "objective") ?? unknownFinding();
  const approaches = working.approaches.flatMap((finding, index) => {
    const validated = validateFinding(finding, `approaches[${index}]`);
    return validated ? [validated] : [];
  });
  const humanInterventions = working.humanInterventions.flatMap(
    (finding, index) => {
      const validated = validateFinding(finding, `humanInterventions[${index}]`, {
        allowedSourceClasses: HUMAN_INTERVENTION_SOURCES,
        requiresEvidence: true
      });
      return validated ? [validated] : [];
    }
  );
  const turningPoints = working.turningPoints.flatMap((finding, index) => {
    const target = `turningPoints[${index}]`;
    const validated = validateFinding(finding, target);
    if (!validated) {
      return [];
    }
    const amended = amendTurningPointCitations(
      validated,
      target,
      evidenceById,
      evidenceOrder,
      actions
    );
    const invalidReason = turningPointInvalidReason(
      amended,
      evidenceById,
      evidenceOrder
    );
    if (invalidReason !== null) {
      reject(
        actions,
        target,
        invalidReason,
        amended.evidenceIds
      );
      return [];
    }
    return [amended];
  });
  const codexContributions = working.codexContributions.flatMap(
    (finding, index) => {
      const validated = validateFinding(finding, `codexContributions[${index}]`, {
        allowedSourceClasses: CODEX_CONTRIBUTION_SOURCES,
        requiresEvidence: true
      });
      return validated ? [validated] : [];
    }
  );
  const reportedOutcome = working.reportedOutcome
    ? validateFinding(working.reportedOutcome, "reportedOutcome", {
        allowedSourceClasses: REPORTED_OUTCOME_SOURCES,
        requiresEvidence: true,
        requiresKnownValue: true
      })
    : null;
  const candidateHasResultBearingOutcomeEvidence =
    working.independentlySupportedOutcome !== null &&

    hasResultBearingOutcomeEvidence(
      working.independentlySupportedOutcome,
      evidenceById
    );
  let independentlySupportedOutcome = working.independentlySupportedOutcome
    ? validateFinding(
        working.independentlySupportedOutcome,
        "independentlySupportedOutcome",
        {
          allowedSourceClasses: ACTIVITY_SOURCES,
          requiresEvidence: true,
          requiresKnownValue: candidateHasResultBearingOutcomeEvidence
        }
      )
    : null;
  const evidenceGaps = working.evidenceGaps.flatMap((finding, index) => {
    const validated = validateFinding(finding, `evidenceGaps[${index}]`);
    return validated ? [validated] : [];
  });

  const leadershipInsights = working.leadershipInsights.flatMap((finding, index) => {
    if (index >= 2) {
      reject(
        actions,
        `leadershipInsights[${index}]`,
        "At most two leadership insights are allowed.",
        finding.evidenceIds
      );
      return [];
    }
    const validated = validateFinding(finding, `leadershipInsights[${index}]`, {
      requiredBasis: "inference"
    });
    return validated ? [validated] : [];
  });

  let outcomeSupport = working.outcomeSupport;
  let attemptOnlyOutcomeSupportCorrected = false;
  if (
    (outcomeSupport === "independently_supported" ||
      outcomeSupport === "contradicted") &&
    independentlySupportedOutcome !== null &&
    !hasResultBearingOutcomeEvidence(
      independentlySupportedOutcome,
      evidenceById
    )
  ) {
    const originalOutcomeSupport = outcomeSupport;
    const finalOutcomeSupport =
      reportedOutcome === null ? "unknown" : "reported_only";
    const evidenceIds = independentlySupportedOutcome.evidenceIds;
    const basisWasDowngraded = independentlySupportedOutcome.basis !== "unknown";
    independentlySupportedOutcome = asUnknownFinding(
      independentlySupportedOutcome
    );
    downgrade(
      actions,
      "outcomeSupport",
      `Outcome support changed from ${originalOutcomeSupport} to ${finalOutcomeSupport}. Cited evidence ${evidenceIds.join(", ")} contains no ${formatSourceClasses(RESULT_BEARING_OUTCOME_SOURCE_CLASSES)} evidence. A ${formatSourceClasses(TOOL_ATTEMPT_SOURCE_CLASSES)} proves an action was initiated but not what result occurred. The independently supported outcome finding was preserved${basisWasDowngraded ? " and its basis was downgraded to unknown" : " with its unknown basis"}.`,
      evidenceIds,
      finalOutcomeSupport === "reported_only"
        ? "outcome_support_attempt_only_to_reported_only"
        : "outcome_support_attempt_only_to_unknown"
    );
    outcomeSupport = finalOutcomeSupport;
    attemptOnlyOutcomeSupportCorrected = true;
  }

  if (!attemptOnlyOutcomeSupportCorrected) {
    const inconsistentReason = outcomeConsistencyReason(
      outcomeSupport,
      reportedOutcome,
      independentlySupportedOutcome
    );
    if (inconsistentReason !== null) {
      downgrade(actions, "outcomeSupport", inconsistentReason, [
        ...(reportedOutcome?.evidenceIds ?? []),
        ...(independentlySupportedOutcome?.evidenceIds ?? [])
      ]);
      outcomeSupport = "unknown";
    }
  }

  const analysis = AnalysisSchema.parse({
    objective,
    approaches,
    humanInterventions,
    turningPoints,
    codexContributions,
    reportedOutcome,
    independentlySupportedOutcome,
    outcomeSupport,
    evidenceGaps,
    leadershipInsights
  });
  const summary = ValidationSummarySchema.parse({
    schemaVersion: 1,
    runId,
    validatedAt: now.toISOString(),
    rejectedCount: actions.filter((entry) => entry.action === "rejected").length,
    downgradedCount: actions.filter((entry) => entry.action === "downgraded").length,
    amendedCount: actions.filter((entry) => entry.action === "amended").length,
    actions
  });

  return { analysis, summary };
}

function amendTurningPointCitations(
  finding: CandidateAnalysis["turningPoints"][number],
  target: string,
  evidenceById: Map<string, EvidenceItem>,
  evidenceOrder: Map<string, number>,
  actions: ValidationSummary["actions"]
): CandidateAnalysis["turningPoints"][number] {
  const canonicalIds = new Set(finding.evidenceIds);
  const addedIds = [
    ...finding.beforeEvidenceIds,
    ...finding.afterEvidenceIds
  ].filter(
    (id, index, ids) =>
      !canonicalIds.has(id) &&
      ids.indexOf(id) === index &&
      evidenceById.has(id) &&
      evidenceOrder.has(id)
  );
  if (addedIds.length === 0) {
    return finding;
  }

  const evidenceIds = [...new Set([...finding.evidenceIds, ...addedIds])].sort(
    (left, right) =>
      (evidenceOrder.get(left) as number) - (evidenceOrder.get(right) as number)
  );
  actions.push({
    action: "amended",
    code: "turning_point_citations_completed",
    target,
    reason: `Added temporal evidence missing from canonical citations: ${addedIds.join(", ")}.`,
    evidenceIds: addedIds
  });
  return { ...finding, evidenceIds };
}

function turningPointInvalidReason(
  finding: CandidateAnalysis["turningPoints"][number],
  evidenceById: Map<string, EvidenceItem>,
  evidenceOrder: Map<string, number>
): string | null {
  if (
    finding.beforeEvidenceIds.length === 0 ||
    finding.afterEvidenceIds.length === 0
  ) {
    return "Turning point requires nonempty beforeEvidenceIds and afterEvidenceIds.";
  }

  const allTemporalIds = [
    ...finding.beforeEvidenceIds,
    ...finding.afterEvidenceIds
  ];
  const invalidTemporalIds = allTemporalIds.filter(
    (id) => !evidenceById.has(id) || !evidenceOrder.has(id)
  );
  if (invalidTemporalIds.length > 0) {
    return `Turning point cites nonexistent temporal evidence: ${[
      ...new Set(invalidTemporalIds)
    ].join(", ")}.`;
  }

  const beforeOrder = finding.beforeEvidenceIds.map(
    (id) => evidenceOrder.get(id) as number
  );
  const afterOrder = finding.afterEvidenceIds.map(
    (id) => evidenceOrder.get(id) as number
  );
  const ordered = Math.max(...beforeOrder) < Math.min(...afterOrder);
  if (!ordered) {
    return "Turning point requires all before evidence to occur strictly before all after evidence.";
  }
  const afterIncludesActivity = finding.afterEvidenceIds.some((id) => {
    const item = evidenceById.get(id);
    return item !== undefined && ACTIVITY_SOURCES.has(item.sourceClass);
  });
  if (!afterIncludesActivity) {
    return "Turning point requires activity evidence on the after side.";
  }
  return null;
}

function outcomeConsistencyReason(
  support: CandidateAnalysis["outcomeSupport"],
  reported: CandidateFinding | null,
  independent: CandidateFinding | null
): string | null {
  switch (support) {
    case "reported_only":
      return reported !== null && independent === null
        ? null
        : "reported_only requires a reported outcome and no independently supported outcome.";
    case "independently_supported":
      return independent !== null
        ? null
        : "independently_supported requires a valid independently supported outcome.";
    case "contradicted":
      return reported !== null && independent !== null
        ? null
        : "contradicted requires both reported and independently supported outcomes.";
    case "unknown":
      return null;
  }
}

function allSourcesAllowed(
  evidence: EvidenceItem[],
  allowed: ReadonlySet<SourceClass>
): boolean {
  return evidence.every((item) => allowed.has(item.sourceClass));
}

function hasResultBearingOutcomeEvidence(
  finding: CandidateFinding,
  evidenceById: Map<string, EvidenceItem>
): boolean {
  return finding.evidenceIds.some((id) => {
    const item = evidenceById.get(id);
    return (
      item !== undefined &&
      RESULT_BEARING_OUTCOME_SOURCES.has(item.sourceClass)
    );
  });
}

function asUnknownFinding<T extends CandidateFinding>(finding: T): T {
  const {
    confidence: _confidence,
    confidenceReason: _confidenceReason,
    ...withoutConfidence
  } = finding;
  return { ...withoutConfidence, basis: "unknown" } as T;
}

function downgradeToInference<T extends CandidateFinding>(
  finding: T,
  target: string,
  reason: string,
  actions: ValidationSummary["actions"]
): T {
  downgrade(actions, target, reason, finding.evidenceIds);
  return {
    ...finding,
    basis: "inference",
    confidence: finding.confidence ?? "low",
    confidenceReason:
      finding.confidenceReason ??
      "Validator downgraded the claimed basis; confidence is conservatively low."
  } as T;
}

function reject(
  actions: ValidationSummary["actions"],
  target: string,
  reason: string,
  evidenceIds: string[]
): void {
  actions.push({ action: "rejected", target, reason, evidenceIds });
}

function downgrade(
  actions: ValidationSummary["actions"],
  target: string,
  reason: string,
  evidenceIds: string[],
  code?: ValidationActionCode
): void {
  actions.push({
    action: "downgraded",
    ...(code ? { code } : {}),
    target,
    reason,
    evidenceIds
  });
}

function emptyAnalysis(): CandidateAnalysis {
  return {
    objective: unknownFinding(),
    approaches: [],
    humanInterventions: [],
    turningPoints: [],
    codexContributions: [],
    reportedOutcome: null,
    independentlySupportedOutcome: null,
    outcomeSupport: "unknown",
    evidenceGaps: [],
    leadershipInsights: []
  };
}

import { existsSync, realpathSync } from "node:fs";
import { dirname, relative, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import type {
  AnalysisProvider,
  AnalysisProviderResult
} from "../src/analysis-provider.ts";
import {
  AnalysisRunStageError,
  persistAnalysisRun,
  serializeJson,
  type AnalysisRunArtifacts
} from "../src/analysis-run-store.ts";
import { readCodexSessionFile } from "../src/codex-session-adapter.ts";
import {
  buildEvidenceBundle,
  measureEvidenceCorpus,
  type EvidenceBundle,
  type EvidenceCorpusStatus
} from "../src/evidence-bundle.ts";
import { OpenAIAnalysisProvider } from "../src/openai-analysis-provider.ts";
import { runProviderAnalysisForBundle } from "../src/provider-analysis-run.ts";
import { rebuildStaticReportIndex } from "../src/report-index.ts";
import {
  buildStructuralSessionReceipt,
  createFullReportDisposition
} from "../src/session-disposition.ts";
import { persistLatestSessionDisposition } from "../src/session-disposition-store.ts";
import { generateSessionReport } from "./report-session.ts";
import { resolveSessionFile } from "./report-session.ts";

const SCRIPT_PATH = fileURLToPath(import.meta.url);
const PROJECT_ROOT = resolve(dirname(SCRIPT_PATH), "..");

export type LiveAnalysisResult =
  | {
      kind: "success";
      artifacts: AnalysisRunArtifacts;
      summary: {
        rejectedCount: number;
        downgradedCount: number;
        amendedCount: number;
      };
      dispositionPath: string;
      indexPath: string;
    }
  | {
      kind: "failure";
      failureKind:
        | Exclude<AnalysisProviderResult["kind"], "success">
        | "bundle_too_large";
      message: string;
      artifacts: AnalysisRunArtifacts;
    };

type Output = { write(value: string): unknown };

export class ManualAnalysisIntegrationError extends Error {
  readonly stage:
    | "final_disposition_persistence"
    | "report_index_rebuild";
  readonly artifacts: AnalysisRunArtifacts;
  readonly dispositionPath?: string;

  constructor(
    stage:
      | "final_disposition_persistence"
      | "report_index_rebuild",
    message: string,
    artifacts: AnalysisRunArtifacts,
    dispositionPath?: string,
    options?: { cause?: unknown }
  ) {
    super(message, options);
    this.name = "ManualAnalysisIntegrationError";
    this.stage = stage;
    this.artifacts = artifacts;
    this.dispositionPath = dispositionPath;
  }
}

export function generateDryRun(
  projectRoot: string,
  selector: string = "latest"
): {
  bundle: EvidenceBundle;
  corpusStatus: EvidenceCorpusStatus;
  serializedBundle: string;
  artifacts: AnalysisRunArtifacts;
} {
  const { root, bundle } = loadEvidenceBundle(projectRoot, selector);
  const corpusStatus = measureEvidenceCorpus(bundle);
  const serializedBundle = serializeJson(bundle);
  const artifacts = persistAnalysisRun(root, bundle, {
    metadata: corpusMetadata(bundle, selector, "dry_run", "completed", corpusStatus)
  });
  return { bundle, corpusStatus, serializedBundle, artifacts };
}

export async function runLiveAnalysis(options: {
  projectRoot: string;
  selector?: string;
  provider: AnalysisProvider;
  now?: Date;
}): Promise<LiveAnalysisResult> {
  const selector = options.selector ?? "latest";
  const { root, bundle } = loadEvidenceBundle(options.projectRoot, selector);
  const corpusStatus = measureEvidenceCorpus(bundle);
  const now = options.now ?? new Date();
  const providerRun = await runProviderAnalysisForBundle({
    projectRoot: root,
    bundle,
    selector,
    provider: options.provider,
    now,
    corpusStatus
  });
  if (providerRun.kind === "failure") return providerRun;

  const receipt = buildStructuralSessionReceipt(
    bundle,
    corpusStatus,
    now.toISOString()
  );
  let persistedDisposition;
  try {
    persistedDisposition = persistLatestSessionDisposition(
      root,
      createFullReportDisposition(receipt, {
        runId: providerRun.artifacts.runId,
        analysisArtifact: "analysis.json",
        validationSummaryArtifact: "validation-summary.json",
        renderedArtifacts: {
          markdown: "report.md",
          html: "report.html"
        }
      })
    );
  } catch (error) {
    throw new ManualAnalysisIntegrationError(
      "final_disposition_persistence",
      `Final full-report disposition persistence failed: ${error instanceof Error ? error.message : String(error)}`,
      providerRun.artifacts,
      undefined,
      { cause: error }
    );
  }

  let rebuiltIndex;
  try {
    rebuiltIndex = rebuildStaticReportIndex(root, now);
  } catch (error) {
    throw new ManualAnalysisIntegrationError(
      "report_index_rebuild",
      `Static report inbox rebuilding failed: ${error instanceof Error ? error.message : String(error)}`,
      providerRun.artifacts,
      persistedDisposition.path,
      { cause: error }
    );
  }

  return {
    kind: "success",
    artifacts: providerRun.artifacts,
    summary: providerRun.summary,
    dispositionPath: persistedDisposition.path,
    indexPath: rebuiltIndex.path
  };
}

export async function runAnalyzeCommand(options: {
  projectRoot: string;
  args: string[];
  env?: NodeJS.ProcessEnv;
  stdout?: Output;
  stderr?: Output;
  providerFactory?: (apiKey: string) => AnalysisProvider;
  now?: Date;
}): Promise<number> {
  const stdout = options.stdout ?? process.stdout;
  const stderr = options.stderr ?? process.stderr;
  try {
    const { selector, dryRun } = parseArguments(options.args);
    if (dryRun) {
      const result = generateDryRun(options.projectRoot, selector);
      stdout.write(result.serializedBundle);
      stderr.write(`${formatCorpusStatus(result.corpusStatus)}\n`);
      stderr.write(`Bundle saved to ${displayPath(result.artifacts.bundlePath)}\n`);
      return 0;
    }

    const apiKey=[REDACTED:env-secret]
      options.env === undefined
        ? process.env.OPENAI_API_KEY
        : options.env.OPENAI_API_KEY
    )?.trim();
    if (!apiKey) {
      const fallback = generateSessionReport(options.projectRoot, selector);
      stdout.write(
        "OPENAI_API_KEY is not configured; live analysis is unavailable. Showing the deterministic report instead.\n\n"
      );
      stdout.write(`${fallback.markdown}\n`);
      stdout.write(`Deterministic report saved to ${displayPath(fallback.reportPath)}\n`);
      return 0;
    }

    const provider = options.providerFactory
      ? options.providerFactory(apiKey)
      : new OpenAIAnalysisProvider({ apiKey });
    const result = await runLiveAnalysis({
      projectRoot: options.projectRoot,
      selector,
      provider,
      now: options.now
    });
    if (result.kind === "failure") {
      stderr.write(
        `Live analysis failed (${result.failureKind}): ${result.message}\nArtifacts saved to ${displayPath(result.artifacts.directory)}\n`
      );
      return 1;
    }

    stdout.write(`Report saved to ${displayPath(result.artifacts.reportPath ?? result.artifacts.directory)}\n`);
    stdout.write(
      `HTML report saved to ${displayPath(result.artifacts.htmlReportPath ?? result.artifacts.directory)}\n`
    );
    stdout.write(`Report inbox saved to ${displayPath(result.indexPath)}\n`);
    stdout.write(
      `Validation: ${result.summary.rejectedCount} rejected, ${result.summary.downgradedCount} downgraded, ${result.summary.amendedCount} amended.\n`
    );
    return 0;
  } catch (error) {
    if (error instanceof ManualAnalysisIntegrationError) {
      stderr.write(`${error.message}\n`);
      if (error.artifacts.htmlReportPath !== null) {
        stderr.write(
          `HTML report exists at ${displayPath(error.artifacts.htmlReportPath)}\n`
        );
      }
      if (error.dispositionPath !== undefined) {
        stderr.write(
          `Full-report disposition exists at ${displayPath(error.dispositionPath)}\n`
        );
      }
      stderr.write("The report was not successfully added to the report inbox.\n");
      return 1;
    }
    if (error instanceof AnalysisRunStageError) {
      stderr.write(`${error.stage}: ${error.message}\n`);
      stderr.write("No report was successfully added to the report inbox.\n");
      return 1;
    }
    stderr.write(`${error instanceof Error ? error.message : String(error)}\n`);
    return 1;
  }
}

function corpusMetadata(
  bundle: EvidenceBundle,
  selector: string,
  mode: "dry_run" | "live",
  status: "completed" | "failed",
  corpusStatus: EvidenceCorpusStatus
): Record<string, unknown> {
  return {
    schemaVersion: 1,
    mode,
    status,
    selector,
    sessionId: bundle.session.sessionId,
    corpus: corpusStatus
  };
}

function formatCorpusStatus(status: EvidenceCorpusStatus): string {
  return [
    `Complete sanitized session evidence: ${status.serializedCorpusBytes} bytes`,
    `request budget: ${status.requestBudgetBytes} bytes`,
    `evidence: ${status.totalEvidenceCount} total, ${status.retainedEvidenceCount} retained, ${status.omittedEvidenceCount} omitted`,
    `one-request eligible: ${status.eligibleForSingleRequest ? "yes" : "no"}`
  ].join("; ");
}

function loadEvidenceBundle(
  projectRoot: string,
  selector: string
): { root: string; bundle: EvidenceBundle } {
  const root = realpathSync(projectRoot);
  const sessionFile = resolveSessionFile(root, selector);
  if (!existsSync(sessionFile)) {
    throw new Error(`No recording found for ${selector} at ${sessionFile}`);
  }
  const session = readCodexSessionFile(sessionFile);
  if (session.events.length === 0) {
    throw new Error(`No valid hook events found in ${session.sourcePath}`);
  }
  return { root, bundle: buildEvidenceBundle(session) };
}

function parseArguments(args: string[]): { selector: string; dryRun: boolean } {
  const dryRunArguments = args.filter((argument) => argument === "--dry-run");
  const unknownFlags = args.filter(
    (argument) => argument.startsWith("--") && argument !== "--dry-run"
  );
  const selectors = args.filter((argument) => !argument.startsWith("--"));
  if (
    dryRunArguments.length > 1 ||
    unknownFlags.length > 0 ||
    selectors.length > 1
  ) {
    throw new Error("Usage: npm run analyze -- [--dry-run] [latest|session-id]");
  }
  return { selector: selectors[0] ?? "latest", dryRun: dryRunArguments.length === 1 };
}

function displayPath(path: string): string {
  return relative(process.cwd(), path) || path;
}

async function main(): Promise<void> {
  process.exitCode = await runAnalyzeCommand({
    projectRoot: PROJECT_ROOT,
    args: process.argv.slice(2),
    env: process.env
  });
}

const invokedPath = process.argv[1];
if (invokedPath && SCRIPT_PATH === resolve(invokedPath)) {
  void main();
}

